import React, { useEffect, useState } from "react";
import "./Admin.css";

const Admin = () => {
  // --- Состояния для данных ---
  const [stats, setStats] = useState([]);
  const [news, setNews] = useState([]);

  // --- Состояния для форм ---
  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    date: "",
    category: "IT",
    image: ""
  });

  const [newsForm, setNewsForm] = useState({
    title: "",
    content: "",
    date: ""
  });

  // Состояние для редактирования (хранит объект события или null)
  const [editingEvent, setEditingEvent] = useState(null);

  // --- Загрузка данных ---
  const loadStats = () => {
  fetch("http://localhost:5000/admin/stats")
    .then(res => res.json())
    .then(data => {
      console.log("Данные событий с сервера:", data[0]); // Посмотри в консоль браузера!
      if (Array.isArray(data)) setStats(data);
    });
  };

  const loadNews = () => {
    fetch("http://localhost:5000/admin/news")
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) setNews(data);
        else setNews([]);
      })
      .catch(err => console.error("Ошибка загрузки новостей:", err));
  };

  useEffect(() => {
    loadStats();
    loadNews();
  }, []);

  // =========================
  // 🛠 ЛОГИКА СОБЫТИЙ
  // =========================

  // Начать редактирование: заполняем форму данными
  const startEdit = (event) => {
    setEditingEvent(event);
    setForm({
      title: event.title || "",
      description: event.description || "",
      location: event.location || "",
      // Форматируем дату для input datetime-local (гггг-мм-ддTчч:мм)
      date: event.date ? event.date.slice(0, 16) : "",
      category: event.category || "IT",
      image: event.image || ""
    });
    // Плавный скролл к форме
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  // Отмена редактирования
  const cancelEdit = () => {
    setEditingEvent(null);
    setForm({
      title: "",
      description: "",
      location: "",
      date: "",
      category: "IT",
      image: ""
    });
  };

  // Создание или Обновление события
  const handleSubmit = async (e) => {
    e.preventDefault();

    const url = editingEvent 
      ? `http://localhost:5000/admin/events/${editingEvent.id}` // Добавили /admin
      : "http://localhost:5000/admin/events";

    const method = editingEvent ? "PUT" : "POST";

    try {
      const res = await fetch(url, {
        method: method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form)
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error || "Ошибка при сохранении");
        return;
      }

      alert(editingEvent ? "Подію оновлено! ✏️" : "Подію створено! ✨");
      cancelEdit();
      loadStats();
    } catch (err) {
      console.error(err);
      alert("Ошибка сервера");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Видалити цю подію?")) return;
    try {
      const res = await fetch(`http://localhost:5000/events/${id}`, { method: "DELETE" });
      if (res.ok) {
        setStats(prev => prev.filter(event => event.id !== id));
      }
    } catch (err) {
      console.error(err);
    }
  };

  // =========================
  // 📰 ЛОГИКА НОВОСТЕЙ
  // =========================

  const handleAddNews = async (e) => {
    e.preventDefault();
    if (!newsForm.title || !newsForm.content || !newsForm.date) {
      alert("Заповніть все поля новини");
      return;
    }

    try {
      const res = await fetch("http://localhost:5000/admin/news", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newsForm)
      });

      if (res.ok) {
        alert("Новину додано! 📰");
        setNewsForm({ title: "", content: "", date: "" });
        loadNews();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleDeleteNews = async (id) => {
    if (!window.confirm("Видалити новину?")) return;
    try {
      const res = await fetch(`http://localhost:5000/admin/news/${id}`, { method: "DELETE" });
      if (res.ok) {
        setNews(prev => prev.filter(n => n.id !== id));
      }
    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className="admin-page">
      <h1>Адмін панель</h1>

      {/* ➕ ФОРМА СОБЫТИЙ (Сверху для удобства редактирования) */}
      <div className="admin-form">
        <h2>{editingEvent ? "✏️ Редагувати подію" : "➕ Додати нову подію"}</h2>
        <form onSubmit={handleSubmit}>
          <input
            placeholder="Назва події"
            value={form.title}
            onChange={(e) => setForm({ ...form, title: e.target.value })}
            required
          />
          <input
            placeholder="Короткий опис"
            value={form.description}
            onChange={(e) => setForm({ ...form, description: e.target.value })}
          />
          <input
            placeholder="Місто / Локація"
            value={form.location}
            onChange={(e) => setForm({ ...form, location: e.target.value })}
          />
          <input
            type="datetime-local"
            value={form.date}
            onChange={(e) => setForm({ ...form, date: e.target.value })}
            required
          />
          <select value={form.category} onChange={(e) => setForm({ ...form, category: e.target.value })}>
            <option>IT</option>
            <option>Business</option>
            <option>Design</option>
            <option>Marketing</option>
            <option>Education</option>
          </select>
          <input
            placeholder="URL зображення"
            value={form.image}
            onChange={(e) => setForm({ ...form, image: e.target.value })}
          />
          
          <div className="form-buttons">
            <button type="submit" className="submit-btn">
              {editingEvent ? "Зберегти зміни" : "Створити подію"}
            </button>
            {editingEvent && (
              <button type="button" className="cancel-btn" onClick={cancelEdit}>
                Скасувати
              </button>
            )}
          </div>
        </form>
      </div>

      <hr />

      {/* 📊 СПИСОК СОБЫТИЙ */}
      <div className="admin-stats">
        <h2>Управління подіями</h2>
        {stats.length > 0 ? (
          stats.map(event => (
            <div className="admin-stats">
  <h2>Управління подіями</h2>
  {stats.length > 0 ? (
    stats.map(event => (
      <div key={event.id} className="stat-card">
        <div className="card-info">
          <h3>{event.title}</h3>
          <p>👥 Реєстрацій: <strong>{event.registrations || 0}</strong></p>
          
          {/* Исправленные строки ниже: */}
          <p>📍 {event.location || "Місце не вказано"}</p>
          <p>📅 {event.date ? new Date(event.date).toLocaleString('uk-UA', {
            day: '2-digit',
            month: '2-digit',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
          }) : "Дата не вказана"}</p>
        </div>

        <div className="card-actions">
          <button className="edit-btn" onClick={() => startEdit(event)}>
            Редагувати
          </button>
          <button className="delete-btn" onClick={() => handleDelete(event.id)}>
            Видалити
          </button>
        </div>
      </div>
    ))
  ) : (
    <p>Подій поки немає...</p>
  )}
</div>
          ))
        ) : (
          <p>Подій поки немає...</p>
        )}
      </div>

      <hr />

      {/* 📰 НОВОСТИ */}
      <div className="admin-section-split">
        <div className="admin-form">
          <h2>Додати новину</h2>
          <form onSubmit={handleAddNews}>
            <input
              placeholder="Заголовок новини"
              value={newsForm.title}
              onChange={(e) => setNewsForm({ ...newsForm, title: e.target.value })}
            />
            <textarea
              placeholder="Текст новини"
              value={newsForm.content}
              onChange={(e) => setNewsForm({ ...newsForm, content: e.target.value })}
            />
            <input
              type="datetime-local"
              value={newsForm.date}
              onChange={(e) => setNewsForm({ ...newsForm, date: e.target.value })}
            />
            <button type="submit">Опублікувати новину</button>
          </form>
        </div>

        <div className="admin-stats">
          <h2>Список новин</h2>
          {news.map(item => (
            <div key={item.id} className="stat-card">
              <div className="card-info">
                <h3>{item.title}</h3>
                <p>{new Date(item.date).toLocaleDateString()}</p>
              </div>
              <button className="delete-btn" onClick={() => handleDeleteNews(item.id)}>
                Видалити
              </button>
            </div>
          ))}
        </div>
      </div>

    </div>
  );
};

export default Admin;
